CREATE TABLE "students" ("id" TEXT NOT NULL, "data" JSONB NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "students_pkey" PRIMARY KEY ("id"));
CREATE TABLE "payments" ("id" TEXT NOT NULL, "data" JSONB NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "payments_pkey" PRIMARY KEY ("id"));
CREATE TABLE "events" ("id" TEXT NOT NULL, "data" JSONB NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "events_pkey" PRIMARY KEY ("id"));
CREATE TABLE "routines" ("id" TEXT NOT NULL, "data" JSONB NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "routines_pkey" PRIMARY KEY ("id"));
CREATE TABLE "evaluations" ("id" TEXT NOT NULL, "data" JSONB NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "evaluations_pkey" PRIMARY KEY ("id"));
CREATE TABLE "coach_settings" ("id" TEXT NOT NULL, "data" JSONB NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "coach_settings_pkey" PRIMARY KEY ("id"));
CREATE TABLE "classes" ("id" TEXT NOT NULL, "title" TEXT NOT NULL, "date" TIMESTAMP(3) NOT NULL, "startTime" TEXT NOT NULL, "endTime" TEXT NOT NULL, "location" TEXT NOT NULL, "capacity" INTEGER NOT NULL, "status" TEXT NOT NULL DEFAULT 'programada', "description" TEXT NOT NULL DEFAULT '', "students" JSONB NOT NULL DEFAULT '[]', "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "classes_pkey" PRIMARY KEY ("id"));
